const https = require('https');

function fetchSlackHistory(channel, token, oldest, latest) {
  return new Promise((resolve, reject) => {
    const options = {
      hostname: 'slack.com',
      path: `/api/conversations.history?channel=${channel}&oldest=${oldest}&latest=${latest}`,
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${token}`,
        'Content-Type': 'application/x-www-form-urlencoded'
      },
      timeout: 5000
    };
    const req = https.get(options, (res) => {
      let data = '';
      res.on('data', (chunk) => { data += chunk; });
      res.on('end', () => {
        if (res.statusCode === 200) {
          try {
            const json = JSON.parse(data);
            if (json.ok) {
              resolve(json.messages || []);
            } else {
              reject(new Error(`Slack API error: ${json.error}`));
            }
          } catch (e) {
            reject(new Error(`Failed to parse JSON response: ${e.message}`));
          }
        } else {
          reject(new Error(`HTTP Status ${res.statusCode}`));
        }
      });
    });
    req.on('error', (err) => reject(err));
    req.on('timeout', () => {
      req.destroy();
      reject(new Error('Request Timeout'));
    });
  });
}

let startDateStr, endDateStr;
try {
  startDateStr = $('Ingestion Date Range Parameters').first().json.start_date;
  endDateStr = $('Ingestion Date Range Parameters').first().json.end_date;
} catch (e) {
  console.log('[Fetch Slack] Could not read date range from Ingestion Date Range Parameters:', e.message);
}

const yesterday = new Date();
yesterday.setDate(yesterday.getDate() - 1);
const today = new Date();

let startDate = startDateStr ? new Date(startDateStr + 'T00:00:00Z') : yesterday;
let endDate = endDateStr ? new Date(endDateStr + 'T00:00:00Z') : today;

const oldest = Math.floor(startDate.getTime() / 1000);
const latest = Math.floor(endDate.getTime() / 1000);

const results = [];
const items = $input.all();

for (const item of items) {
  const { channel_db_id, channel_id, channel_name, token } = item.json;
  if (!token || !channel_id) continue;

  try {
    const messages = await fetchSlackHistory(channel_id, token, oldest, latest);
    for (const msg of messages) {
      if (msg.subtype && msg.subtype !== 'bot_message') continue;

      const messageId = `${channel_id}_${msg.ts}`;
      const created_at = new Date(parseFloat(msg.ts) * 1000).toISOString();
      const cleanTs = msg.ts.replace('.', '');
      const url = `https://slack.com/archives/${channel_id}/p${cleanTs}`;

      results.push({
        id: messageId,
        channel_db_id: channel_db_id,
        author: msg.user || msg.bot_id || 'unknown',
        content: msg.text || '',
        url: url,
        created_at: created_at,
        processed: 0
      });
    }
  } catch (error) {
    console.error(`Error fetching channel ${channel_name} (${channel_id}):`, error.message);
  }
}

return results;
